  city = EXCLUDED.city,
  country = EXCLUDED.country,
  country_code = EXCLUDED.country_code,
  continent = EXCLUDED.continent,
  region = EXCLUDED.region,
  latitude = EXCLUDED.latitude,
  longitude = EXCLUDED.longitude,
  address = EXCLUDED.address,
  designated_2017 = EXCLUDED.designated_2017,
  designated_2022 = EXCLUDED.designated_2022,
  designation_count = EXCLUDED.designation_count,
  designation_state = EXCLUDED.designation_state,
  is_iebc_confirmed_2027 = EXCLUDED.is_iebc_confirmed_2027,
  updated_at = NOW();
